onClick:
{{
  (() => {
    // Verifica se o campo está vazio, ignorando espaços em branco
    if (!n_denuncia_animal.text || n_denuncia_animal.text.trim() === "") {
      showAlert('Por favor, preencha o número da denúncia para realizar o cadastro.', 'warning');
      return; // Interrompe a execução do código aqui
    }

    // Se o campo estiver preenchido, executa o cadastro normalmente
    Query_Salvar_Animal.run()
      .then(() => {
         showAlert('Cadastro realizado com sucesso!', 'success');

         const camposParaLimpar = [
           "Select1",
           "classif_denun", 
           "n_denuncia_animal",
           "telefone_animal", 
           "email_animal", 
           "data_e_hora_denuncia",      
           "Denunciante_animal", 
           "Agressor_animal", 
           "Testemunha_animal", 
           "Text_den_animal", 
           "Select_cidade", 
           "Resposta_animal"
         ];

         camposParaLimpar.forEach(nomeDoCampo => resetWidget(nomeDoCampo));
      })
      .catch(() => {
         showAlert('Erro ao salvar os dados no banco.', 'error');
      });
  })()
}}
